import{_ as a,a as e}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as o,o as d,c as n,a2 as i}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Limity nahrávání pro uživatele","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Safety/user-rate-limits.md","filePath":"cs-CZ/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"cs-CZ/Safety/user-rate-limits.md"};function p(l,t,s,u,v,h){return d(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="limity-nahravani-pro-uzivatele" tabindex="-1">Limity nahrávání pro uživatele <a class="header-anchor" href="#limity-nahravani-pro-uzivatele" aria-label="Permalink to &quot;Limity nahrávání pro uživatele&quot;">​</a></h1><p>Limity nahrávání určují, jak často mohou běžní uživatelé nebo návštěvníci nahrávat soubory z domovské stránky. Pomáhají zabránit zneužití veřejné upload stránky.</p><p>Tato funkce ovlivňuje pouze uploady z domovské stránky. Uploady administrátora a uploady provedené přes API Tokens těmito limity omezené nejsou.</p><h2 id="kde-nastavit" tabindex="-1">Kde nastavit <a class="header-anchor" href="#kde-nastavit" aria-label="Permalink to &quot;Kde nastavit&quot;">​</a></h2><p>Otevřete administraci a přejděte na:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+a+'" alt="Nastavení limitů uživatele" loading="lazy"></p><h2 id="zapnuti-limitu" tabindex="-1">Zapnutí limitů <a class="header-anchor" href="#zapnuti-limitu" aria-label="Permalink to &quot;Zapnutí limitů&quot;">​</a></h2><p>Po zapnutí <code>Enable Rate Limits</code> ImgBed sleduje nedávné uploady podle IP adresy nahrávajícího.</p><p>Výchozí hodnoty:</p><table tabindex="0"><thead><tr><th>Nastavení</th><th>Výchozí</th><th>Popis</th></tr></thead><tbody><tr><td>Detekční okno</td><td>1,5 hodiny</td><td>Jak daleko zpětně se počítají záznamy uploadu.</td></tr><tr><td>Maximální počet souborů</td><td>20</td><td>Nejvyšší počet souborů povolený v detekčním okně.</td></tr><tr><td>Limit jednoho souboru</td><td>20 MB</td><td>Maximální velikost jednoho souboru.</td></tr><tr><td>Celkový limit uploadu</td><td>200 MB</td><td>Maximální celková velikost uploadu v detekčním okně.</td></tr></tbody></table><p>Například při okně 1,5 hodiny, 20 souborech, 20 MB na soubor a 200 MB celkem se uploady ze stejné IP zablokují, jakmile je překročen kterýkoli nastavený limit.</p><h2 id="vylouceni-typu-souboru" tabindex="-1">Vyloučení typů souborů <a class="header-anchor" href="#vylouceni-typu-souboru" aria-label="Permalink to &quot;Vyloučení typů souborů&quot;">​</a></h2><p><code>Excluded upload file types</code> blokuje běžným uživatelům nebo návštěvníkům nahrávání vybraných kategorií souborů.</p><p>Dostupné kategorie:</p><table tabindex="0"><thead><tr><th>Typ</th><th>Popis</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif a podobné obrazové soubory</td></tr><tr><td>Videos</td><td>mp4, webm, mov a podobné video soubory</td></tr><tr><td>Audio</td><td>mp3, flac, wav a podobné audio soubory</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx a podobné dokumenty</td></tr><tr><td>Other</td><td>Soubory mimo uvedené kategorie, například zip, rar, exe, apk</td></tr></tbody></table><p>Ve výchozím stavu není typ vybraný, což znamená, že je povolený.</p><p>Kliknutím se typ zvýrazní, což znamená, že je blokovaný.</p><p>Pokud je vybráno <code>Other</code>, návštěvníci nahrávající zip nebo rar budou zablokováni a uvidí zprávu, že tento typ souboru není podporován.</p><h2 id="blokovaci-zpravy" tabindex="-1">Blokovací zprávy <a class="header-anchor" href="#blokovaci-zpravy" aria-label="Permalink to &quot;Blokovací zprávy&quot;">​</a></h2><p>Když se spustí limit, uživatelé uvidí odpovídající zprávu:</p><p><img src="'+e+'" alt="Zpráva o příliš častém uploadu" loading="lazy"></p><table tabindex="0"><thead><tr><th>Situace</th><th>Význam zprávy</th></tr></thead><tbody><tr><td>Jeden soubor je příliš velký</td><td>Soubor je příliš velký a měl by se před nahráním zkomprimovat.</td></tr><tr><td>Typ souboru je blokovaný</td><td>Tento typ souboru není podporován. Odstraňte ho a zkuste to znovu.</td></tr><tr><td>Uploady jsou příliš časté</td><td>Nedávné uploady jsou příliš časté, zobrazí se čas dalšího pokusu.</td></tr><tr><td>Celková velikost je příliš vysoká</td><td>Nedávná celková velikost uploadu je příliš vysoká, zobrazí se čas dalšího pokusu.</td></tr></tbody></table><h2 id="kdy-zapnout" tabindex="-1">Kdy zapnout <a class="header-anchor" href="#kdy-zapnout" aria-label="Permalink to &quot;Kdy zapnout&quot;">​</a></h2><p>Zapněte limity uživatele, pokud je upload stránka veřejně dostupná.</p><p>Časté důvody:</p><ul><li>obáváte se skriptovaných hromadných uploadů.</li><li>chcete omezit velké uploady návštěvníků.</li><li>chcete, aby běžní uživatelé nahrávali jen obrázky, ne archivy nebo instalátory.</li><li>chcete ponechat veřejný upload dostupný, ale mít pod kontrolou využití zdrojů.</li></ul><p>Pokud je web jen pro vás nebo mohou nahrávat jen administrátoři, můžete funkci nechat vypnutou.</p>',28)])])}const y=o(r,[["render",p]]);export{c as __pageData,y as default};
